# Minimal incident detection hook — runs after every prediction batch
def check_batch_for_anomalies(batch_outputs, thresholds):
    confidence_drop = batch_outputs['confidence'].mean() < thresholds['min_confidence']
    refusal_spike = batch_outputs['refused'].mean() > thresholds['max_refusal_rate']
    if confidence_drop or refusal_spike:
        alert = {
            'severity': 'HIGH' if confidence_drop and refusal_spike else 'MEDIUM',
            'confidence_mean': batch_outputs['confidence'].mean(),
            'refusal_rate': batch_outputs['refused'].mean(),
        }
        page_oncall(alert)  # page model risk team
        write_audit_event('ANOMALY_DETECTED', alert)

# Simplified AIA risk matrix computation
SEVERITY = {'negligible': 1, 'minor': 2, 'moderate': 3, 'major': 4, 'critical': 5}
PROBABILITY = {'rare': 1, 'unlikely': 2, 'possible': 3, 'likely': 4, 'almost_certain': 5}

def risk_score(severity, probability):
    return SEVERITY[severity] * PROBABILITY[probability]

def risk_tier(score):
    if score <= 4: return 'LOW'
    if score <= 10: return 'MEDIUM'
    if score <= 16: return 'HIGH'
    return 'CRITICAL'

# Example harm assessment entry
harm = {
    'description': 'Incorrect loan denial for protected group',
    'severity': 'major',
    'probability': 'possible',
}
score = risk_score(harm['severity'], harm['probability'])  # 4 * 3 = 12
print(f"Risk: {risk_tier(score)}")  # HIGH -> requires mandatory mitigation
